import{C as o,o as n,c as s,a5 as a,E as l}from"./chunks/framework.CW28V7p_.js";const h=JSON.parse('{"title":"6. Slashing — deep dive","description":"","frontmatter":{},"headers":[],"relativePath":"module-4/6-slashing-deep.md","filePath":"module-4/6-slashing-deep.md","lastUpdated":1780937944000}'),r={name:"module-4/6-slashing-deep.md"},u=Object.assign(r,{setup(d){const t={id:"m4-6-slashing",title:"🧠 Mini-check: Slashing",intro:"2 питання.",questions:[{type:"compare",q:"Solana slashing — current state vs proposed Alpenglow?",ideal:`Current (Tower BFT, as of 2026):
- Double-vote condition defined у Tower BFT protocol
- Slashing logic implemented у runtime
- BUT not actively triggered/enforced automatically
- Enforcement через social punishment: caught validators removed from SFDP, stake pools withdraw delegations, reputation damage
- Economic disincentive (lost income) > technical slashing currently

Alpenglow proposed:
- Strict automatic enforcement:
  - Double-vote: instant stake slash + validator ejection
  - Equivocation (conflicting blocks signed): same
  - Inactivity beyond threshold: gradual stake reduction
- More similar to Cosmos slashing model
- Higher operational risk для validators — bugs that cause double-signs could destroy stake

Why proposed change: Tower BFT defines but не enforces — relies on goodwill. Alpenglow wants мathematical guarantees, не trust.

Implications для operators: more careful operations needed (avoid running same identity на multiple machines, avoid restoring keypair without ensuring old instance stopped, etc.).`,explanation:"Module 4.6."},{type:"mcq",q:"Як validator може accidentally double-vote?",options:["Running validator identity на two servers simultaneously","Restoring keypair backup on new server без stopping old instance","Cluster restart procedures done improperly","Slow network causes vote retry"],correct:[0,1,2],explanation:"#4 не cause double-vote — protocol handles retries safely. Module 4.6."}]};return(c,e)=>{const i=o("Quiz");return n(),s("div",null,[e[0]||(e[0]=a(`<h1 id="_6-slashing-—-deep-dive" tabindex="-1">6. Slashing — deep dive <a class="header-anchor" href="#_6-slashing-—-deep-dive" aria-label="Permalink to &quot;6. Slashing — deep dive&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>Slashing</strong> = penalty (stake reduction) для malicious or buggy validator behavior. Solana has slashing <strong>conditions defined</strong> but currently <strong>not actively enforced</strong> automatically. Alpenglow proposes strict enforcement — higher operational risk requiring careful key management.</p><h2 id="slashing-conditions" tabindex="-1">Slashing conditions <a class="header-anchor" href="#slashing-conditions" aria-label="Permalink to &quot;Slashing conditions&quot;">​</a></h2><h3 id="double-vote" tabindex="-1">Double-vote <a class="header-anchor" href="#double-vote" aria-label="Permalink to &quot;Double-vote&quot;">​</a></h3><p>Validator signs <strong>two conflicting votes</strong> for same slot (e.g., for blocks A and B at slot 100).</p><p>Detection: vote TXs у chain show both signatures from same validator. Mechanically detectable.</p><p>Cause:</p><ul><li><strong>Honest mistake</strong>: bug у validator software signs twice</li><li><strong>Malicious</strong>: deliberately trying to disrupt consensus</li><li><strong>Operational error</strong>: same identity running on two servers (most common cause)</li></ul><h3 id="equivocation-signing-conflicting-blocks" tabindex="-1">Equivocation (signing conflicting blocks) <a class="header-anchor" href="#equivocation-signing-conflicting-blocks" aria-label="Permalink to &quot;Equivocation (signing conflicting blocks)&quot;">​</a></h3><p>Leader signs two different blocks for same slot. Similar to double-vote but for leader output.</p><h3 id="inactivity-proposed" tabindex="-1">Inactivity (proposed) <a class="header-anchor" href="#inactivity-proposed" aria-label="Permalink to &quot;Inactivity (proposed)&quot;">​</a></h3><p>Validator down beyond threshold. Currently → delinquent flag (no rewards). Alpenglow proposes stake reduction over extended inactivity.</p><h2 id="current-state-defined-but-not-enforced" tabindex="-1">Current state: defined but not enforced <a class="header-anchor" href="#current-state-defined-but-not-enforced" aria-label="Permalink to &quot;Current state: defined but not enforced&quot;">​</a></h2><p>Tower BFT (Module 4.2) defines slashing conditions in protocol specification. Runtime can detect violations. But:</p><ul><li><strong>No automatic stake reduction</strong> triggered</li><li><strong>No on-chain enforcement</strong> mechanism active</li><li>Validators caught double-signing — not slashed by protocol</li></ul><h3 id="how-violations-actually-handled-today" tabindex="-1">How violations actually handled today <a class="header-anchor" href="#how-violations-actually-handled-today" aria-label="Permalink to &quot;How violations actually handled today&quot;">​</a></h3><p>Social punishment:</p><ol><li><strong>Caught violators publicized</strong> у Discord/Twitter</li><li><strong>SFDP removal</strong> — Foundation removes stake delegation</li><li><strong>Stake pool withdrawals</strong> — Jito/Marinade pools un-delegate</li><li><strong>Reputation damage</strong> — direct delegators leave</li><li><strong>Income loss</strong> — without delegations, validator unprofitable</li></ol><p>Effectively: economic слашing through community action, not protocol.</p><h3 id="why-this-design" tabindex="-1">Why this design <a class="header-anchor" href="#why-this-design" aria-label="Permalink to &quot;Why this design&quot;">​</a></h3><p>Several reasons:</p><ul><li>Solana focused on performance over strict slashing initially</li><li>Risk of false positives slashing honest operators (bugs у edge cases)</li><li>Easier to evolve без protocol-level enforcement</li><li>Trust community will self-police</li></ul><h2 id="alpenglow-proposed-slashing" tabindex="-1">Alpenglow proposed slashing <a class="header-anchor" href="#alpenglow-proposed-slashing" aria-label="Permalink to &quot;Alpenglow proposed slashing&quot;">​</a></h2><p>SIMD-0326 proposes much stricter mechanism:</p><h3 id="automatic-enforcement" tabindex="-1">Automatic enforcement <a class="header-anchor" href="#automatic-enforcement" aria-label="Permalink to &quot;Automatic enforcement&quot;">​</a></h3><ul><li>Double-vote detected on-chain → instant stake slash</li><li>Equivocation → instant slash + validator ejection</li><li>Slashed funds: burned or redistributed</li></ul><h3 id="inactivity-slashing" tabindex="-1">Inactivity slashing <a class="header-anchor" href="#inactivity-slashing" aria-label="Permalink to &quot;Inactivity slashing&quot;">​</a></h3><p>Gradual stake reduction для extended downtime:</p><ul><li>1 hour down: no penalty</li><li>1 day down: small penalty</li><li>1 week down: significant penalty</li><li>Designed to incentivize liveness, not just safety</li></ul><h3 id="implications-для-operators" tabindex="-1">Implications для operators <a class="header-anchor" href="#implications-для-operators" aria-label="Permalink to &quot;Implications для operators&quot;">​</a></h3><p>Higher operational risk:</p><ul><li>Bug у setup that double-signs → real money loss</li><li>Hardware failure during voting → potentially slashed</li><li>Need more careful key management</li></ul><p>Best practices ще критичніші:</p><ul><li>NEVER run same identity на multiple machines</li><li>ALWAYS verify old instance stopped перед restoring backup</li><li>Test thoroughly on testnet перед mainnet operations</li><li>Use validator software із double-sign protection (vote tracking)</li></ul><h2 id="common-double-vote-pitfalls" tabindex="-1">Common double-vote pitfalls <a class="header-anchor" href="#common-double-vote-pitfalls" aria-label="Permalink to &quot;Common double-vote pitfalls&quot;">​</a></h2><h3 id="pitfall-1-running-validator-twice" tabindex="-1">Pitfall 1: Running validator twice <a class="header-anchor" href="#pitfall-1-running-validator-twice" aria-label="Permalink to &quot;Pitfall 1: Running validator twice&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Server A (production): identity key, voting</span></span>
<span class="line"><span>Server B (testing):    same identity key copied, also voting</span></span>
<span class="line"><span>→ both sign votes для same slots → double-vote!</span></span></code></pre></div><p>Fix: NEVER copy identity to second instance without ensuring first stopped + waited.</p><h3 id="pitfall-2-disaster-recovery-without-coordination" tabindex="-1">Pitfall 2: Disaster recovery without coordination <a class="header-anchor" href="#pitfall-2-disaster-recovery-without-coordination" aria-label="Permalink to &quot;Pitfall 2: Disaster recovery without coordination&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Server A: crashes hard (assumed down)</span></span>
<span class="line"><span>Restore: copy keypair backup до Server B, start validator</span></span>
<span class="line"><span>Server A: comes back up (was network issue, not crash)</span></span>
<span class="line"><span>→ both signing!</span></span></code></pre></div><p>Fix: ALWAYS verify Server A truly down (SSH dead, console confirmation). Wait 5+ minutes before bringing up new instance з same identity.</p><h3 id="pitfall-3-failover-automation" tabindex="-1">Pitfall 3: Failover automation <a class="header-anchor" href="#pitfall-3-failover-automation" aria-label="Permalink to &quot;Pitfall 3: Failover automation&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Watchdog: detects ping failure</span></span>
<span class="line"><span>Action: auto-spawn backup validator з restored identity</span></span>
<span class="line"><span>Reality: network glitch, primary still alive</span></span>
<span class="line"><span>→ both signing!</span></span></code></pre></div><p>Fix: NO auto-failover для identity. Manual confirmation required for safety.</p><h3 id="pitfall-4-identity-rotation-race" tabindex="-1">Pitfall 4: Identity rotation race <a class="header-anchor" href="#pitfall-4-identity-rotation-race" aria-label="Permalink to &quot;Pitfall 4: Identity rotation race&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Old identity X: validator running з X</span></span>
<span class="line"><span>Rotate: set new identity Y via agave-validator set-identity</span></span>
<span class="line"><span>Old validator process: still has X loaded (didn&#39;t restart)</span></span>
<span class="line"><span>→ both X identity AND Y signing concurrently</span></span></code></pre></div><p>Fix: restart validator after identity rotation. Don&#39;t trust hot rotation work без restart.</p><h2 id="double-sign-protection-patterns" tabindex="-1">Double-sign protection patterns <a class="header-anchor" href="#double-sign-protection-patterns" aria-label="Permalink to &quot;Double-sign protection patterns&quot;">​</a></h2><h3 id="slasher-prevention-scripts" tabindex="-1">Slasher prevention scripts <a class="header-anchor" href="#slasher-prevention-scripts" aria-label="Permalink to &quot;Slasher prevention scripts&quot;">​</a></h3><p>External monitoring detect duplicate signing:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Track vote signatures у chain — alert if duplicate</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Custom script сhecking RPC for двох votes from same identity у same slot</span></span></code></pre></div><p>Some Jito-Solana variants ship з built-in double-sign protection (refuse to vote якщо detect conflicting recent vote).</p><h3 id="tower-file-management" tabindex="-1">Tower file management <a class="header-anchor" href="#tower-file-management" aria-label="Permalink to &quot;Tower file management&quot;">​</a></h3><p>Validator stores tower (vote history) у <code>~/.solana/tower-N.bin</code>. Якщо restored validator з old tower → can re-sign already-voted slot.</p><p>Solution: <strong>delete tower file</strong> перш ніж restore on new server. Validator builds new tower from scratch (slower catchup але safe).</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/solana/ledger/tower-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.bin</span></span></code></pre></div><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><h3 id="cluster-restart-sensitivity" tabindex="-1">Cluster restart sensitivity <a class="header-anchor" href="#cluster-restart-sensitivity" aria-label="Permalink to &quot;Cluster restart sensitivity&quot;">​</a></h3><p>З cheatsheet §3 — cluster restart involves identity preservation across servers. Critical:</p><ul><li>Backup keypair (Phase 0)</li><li>New cluster has new genesis = new &quot;session&quot; effectively</li><li>Old votes from old genesis не conflict з new (different cluster)</li></ul><h3 id="alpenglow-risk-profile" tabindex="-1">Alpenglow risk profile <a class="header-anchor" href="#alpenglow-risk-profile" aria-label="Permalink to &quot;Alpenglow risk profile&quot;">​</a></h3><p>Alpenglow community cluster тестує strict slashing scenarios. Якщо bug у your validator setup → real Alpenglow SOL loss (though small amounts на community cluster).</p><p>Mainnet (Tower BFT) less stringent currently. Don&#39;t be complacent — Alpenglow stricter ideology coming.</p><h3 id="hot-identity-rotation" tabindex="-1">Hot identity rotation <a class="header-anchor" href="#hot-identity-rotation" aria-label="Permalink to &quot;Hot identity rotation&quot;">​</a></h3><p>З Module 9.4 — <code>agave-validator set-identity</code> allows rotation без restart. CONVENIENT але:</p><ul><li>If old identity already used для votes recently → vote authority transition careful</li><li>Best practice: stop validator, rotate, restart (avoid hot swap у production)</li></ul><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,68)),l(i,{data:t}),e[1]||(e[1]=a('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#s"><code>Slashing</code></a>, <a href="/glossary#d"><code>Double-sign</code></a>, <a href="/glossary#e"><code>Equivocation</code></a>, <a href="/glossary#t"><code>Tower file</code></a>, <a href="/glossary#i"><code>Identity rotation</code></a>, <a href="/glossary#s"><code>Slashing condition</code></a></p><hr><p><strong>Попередньо:</strong> <a href="/module-4/5-forks">← 5. Forks</a> | <strong>Наступне:</strong> <a href="/module-4/7-recent-simds">7. Recent SIMDs →</a></p>',4))])}}});export{h as __pageData,u as default};
